 23→function getVisibleSectionsByMode(mode) {
 24→  if (mode === 'stock') return ['portfolio_summary', 'holdings', 'stock_detail'];
 25→  if (mode === 'education') return ['calendar', 'daily_briefing', 'quiz_mission'];
