 32→function readSearchToggle(mode) {
 33→  try {
 34→    const value = localStorage.getItem(SEARCH_TOGGLE_KEY);
 35→    if (value === '1') return true;
 36→    if (value === '0') return false;
 37→    return mode === 'stock';
